package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

public class CSVFormatTest {

    @Test
    public void testWithSkipHeaderRecord() {
        // Given
        CSVFormat csvFormat = new CSVFormat(',', '"', QuoteMode.MINIMAL, '#', '\\', true, false, "\r\n",
                "\\N", new Object[]{"Header1", "Header2"}, new String[]{"Comment1", "Comment2"}, false, false, true, true,
                false);

        // When
        CSVFormat result = csvFormat.withSkipHeaderRecord();

        // Then
        assertTrue(result.getSkipHeaderRecord());
    }

    // Add more test cases for other scenarios if needed

}
